    public function getSourceContext(): Source
    {
        return new Source("{% extends 'base.html.twig' %}

{% block title %}{{ produit is defined ? 'Modifier' : 'Ajouter' }} un Produit{% endblock %}

{% block body %}
<div class=\"container\">
    <div class=\"row justify-content-center\">
        <div class=\"col-md-8\">
            <div class=\"card\">
                <div class=\"card-header\">
                    <h3 class=\"text-center\">{{ produit is defined ? 'Modifier' : 'Ajouter' }} un Produit</h3>
                </div>
                <div class=\"card-body\">
                    {{ form_start(form, {'attr': {'class': 'needs-validation', 'novalidate': 'novalidate'}}) }}
                    
                    <div class=\"mb-3\">
                        {{ form_label(form.nom) }}
                        {{ form_widget(form.nom) }}
                        {{ form_errors(form.nom) }}
                    </div>

                    <div class=\"mb-3\">
                        {{ form_label(form.description) }}
                        {{ form_widget(form.description) }}
                        {{ form_errors(form.description) }}
                    </div>

                    <div class=\"mb-3\">
                        {{ form_label(form.prix) }}
                        {{ form_widget(form.prix) }}
                        {{ form_errors(form.prix) }}
                    </div>

                    <div class=\"mb-3\">
                        {{ form_label(form.quantite) }}
                        {{ form_widget(form.quantite) }}
                        {{ form_errors(form.quantite) }}
                    </div>

                    <div class=\"text-center\">
                        {{ form_widget(form.submit) }}
                        <a href=\"{{ path('liste_produits') }}\" class=\"btn btn-secondary\">Annuler</a>
                    </div>

                    {{ form_end(form) }}
                </div>
            </div>
        </div>
    </div>
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
    // Activer la validation Bootstrap
    var forms = document.querySelectorAll('.needs-validation');
    Array.prototype.slice.call(forms).forEach(function(form) {
        form.addEventListener('submit', function(event) {
            if (!form.checkValidity()) {
                event.preventDefault();
                event.stopPropagation();
            }
            form.classList.add('was-validated');
        }, false);
    });
});
</script>
{% endblock %}
", "ProduitForm.html.twig", "C:\\Users\\Nassir\\Produit\\templates\\ProduitForm.html.twig");
